# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ management API endpoint
RABBITMQ_API = 'http://localhost:15672/api'

# Credentials for RabbitMQ admin user
ADMIN_USER = 'admin'
ADMIN_PASSWORD = 'password'

def create_vhost(vhost_name):
    url = f'{RABBITMQ_API}/vhosts/{vhost_name}'
    auth = (ADMIN_USER, ADMIN_PASSWORD)
    response = requests.put(url, auth=auth)
    if response.status_code == 201:
        print(f'VHost {vhost_name} created successfully.')
    else:
        print(f'Failed to create VHost {vhost_name}: {response.text}')

def set_user_permissions(vhost_name, username):
    url = f'{RABBITMQ_API}/permissions/{vhost_name}/{username}'
    auth = (ADMIN_USER, ADMIN_PASSWORD)
    payload = {
        'configure': '^.*',
        'write': '^.*',
        'read': '^.*'
    }
    response = requests.put(url, json=payload, auth=auth)
    if response.status_code == 201:
        print(f'Permissions set for user {username} on VHost {vhost_name}.')
    else:
        print(f'Failed to set permissions for user {username}: {response.text}')

# Example usage
create_vhost('app1_vhost')
set_user_permissions('app1_vhost', 'app1_user')

create_vhost('app2_vhost')
set_user_permissions('app2_vhost', 'app2_user')